import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse(`{"title":"Ben's Bites — 2026-05-16","description":"","frontmatter":{"title":"Ben's Bites — 2026-05-16","date":"2026-05-16T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-16-bens-bites.md","filePath":"research/ai-news/2026-05/2026-05-16-bens-bites.md","lastUpdated":1779796674000}`),s={name:"research/ai-news/2026-05/2026-05-16-bens-bites.md"};function n(i,e,l,h,p,d){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🍔-ben-s-bites-—-2026-05-16" tabindex="-1">🍔 Ben&#39;s Bites — 2026-05-16 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-05-16" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-05-16&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="agents-feedback-tip" tabindex="-1"><a href="https://www.bensbites.com/p/agents-feedback-tip" target="_blank" rel="noreferrer">Agents feedback tip</a> <a class="header-anchor" href="#agents-feedback-tip" aria-label="Permalink to &quot;[Agents feedback tip](https://www.bensbites.com/p/agents-feedback-tip)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-14</em></p><p>Hey folks, I&#39;m testing out something new in my building workflow…</p><p>When an agent asks for feedback it feels like the levels are</p><ol><li><p>type your response</p></li><li><p>voice-to-text your response</p></li><li><p>+ images to your feedback</p></li><li><p>get the agent to use the browser</p></li></ol><p>But I just started screen-recording and talking then giving that file to my agent</p><p><a href="https://substackcdn.com/image/fetch/$s_!Q4Fy!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F4b732846-79a5-4a45-b7a0-1cfc55a2918c_1458x448.png" target="_blank" rel="noreferrer"></a></p><p>This is me, in droid, like 30 mins ago. It pulls together a pretty great visual report you can easily review. I can navigate to other websites or apps and show what good looks like from other people, I can highlight specific points and it&#39;ll recreate those points with GIFs.</p><p>It gives itself an &#39;actions&#39; checklist underneath. And just feels great to have screenshot -&gt; my feedback -&gt; action for the agent.</p><p><a href="https://substackcdn.com/image/fetch/$s_!KXnE!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fda62482a-91c6-4d5c-86e0-9f7c5418b0ba_1596x1546.png" target="_blank" rel="noreferrer"></a></p><p>It&#39;s pretty great so far, and then I&#39;ve got these html files saved in my projects to always refer back to - will be good for a build log too.</p><p>Probably not great for the token conscious out there - and thinking about it, I could probably use ffmpeg to create actual clips of the video if I wanted. Agents read frames well though so it&#39;d be more for me if I did.</p><p>I turned it into a simple skill:</p><p>---</p><p>name: video-to-html</p><p>description: Use when the user wants you to convert their video into a structured HTML document.</p><p>---</p><p>Turn the user&#39;s video into a structured HTML document. Transcribe the video and pull out the keyframes linked to timestamps for important information. When the user is talking about something that is not dynamic, create short GIFs from the keyframes.</p><p>Let me know any cool use-cases or remixes of this 😊</p><hr><p><em>Ben &#39;s Bites is brought to you by <strong><a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Hyperagent from Airtable</a></strong></em></p><blockquote><p><a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Hyperagent</a>, the cloud agent system with full computing environments, is giving $10M in inference credits to help founders build and run agent-first companies. The first 500 qualifying applicants gain access to this limited founder offer. <a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Applications close May 31st</a>.</p></blockquote><hr><h4 id="headlines" tabindex="-1">Headlines <a class="header-anchor" href="#headlines" aria-label="Permalink to &quot;Headlines&quot;">​</a></h4><ul><li><p><strong><a href="https://x.com/ClaudeDevs/status/2054610152817619388" target="_blank" rel="noreferrer">Your Claude plan is changing</a></strong> if you use third-party tools (like Conductor, Zed, Openclaw, T3 Code, etc.) with it.</p><ul><li><p>Separate limit for all such usage. Provided as extra monthly credits equal to the value of your plan.</p></li><li><p>No subsidised tokens, credits won&#39;t roll over and usage after you burn through these credits is billed at API rates.</p></li><li><p>Using Claude in Claude Code, Claude app, etc., stays the same and is separate from this.</p></li><li><p>Starts from June 15th, but they are increasing your <a href="https://x.com/ClaudeDevs/status/2054639777685934564" target="_blank" rel="noreferrer">weekly rate limits</a> by 50% for the next two months.</p></li></ul></li><li><p>Google announced some <strong>Gemini on Android</strong> updates before I/O - add features like auto-completing forms, rambling voice notes to clean text, and some app automations under the name &quot;<strong><a href="https://blog.google/products-and-platforms/platforms/android/gemini-intelligence/" target="_blank" rel="noreferrer">Gemini Intelligence</a></strong> &quot;. They also announced a new class of laptops called <strong><a href="https://blog.google/products-and-platforms/platforms/android/meet-googlebook" target="_blank" rel="noreferrer">Googlebooks</a></strong> , not to be confused with <a href="https://thenewthings.com/p/googlebooks-are-not-google-books" target="_blank" rel="noreferrer">Google Books</a>.</p></li><li><p><strong><a href="https://www.notion.com/product/dev" target="_blank" rel="noreferrer">Notion has a developer platform now</a></strong>. The biggest addition is a markdown API. Also, devs can sync outside data into Notion, build tools for Notion Agents, run code on Notion&#39;s infra, and eventually bring agents like Claude/Codex into Notion as teammates. But I think people who don&#39;t call them developers will use this.</p><ul><li>They also launched a CLI called <strong><a href="https://ntn.dev/" target="_blank" rel="noreferrer">ntn</a></strong>.</li></ul></li><li><p><strong><a href="https://vercel.com/blog/ai-gateway-production-index" target="_blank" rel="noreferrer">Vercel published an AI Gateway production index</a></strong> based on real usage across apps and agents. Anthropic leads spend (61% -- due to opus), Google leads token volume (38% -- due to flash), and agentic workloads are 59% of token usage. Most large teams route across many models instead of betting on one lab.</p></li></ul><hr><p><a href="https://www.bensbites.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><h4 id="my-feed" tabindex="-1">My feed <a class="header-anchor" href="#my-feed" aria-label="Permalink to &quot;My feed&quot;">​</a></h4><ul><li><p>Cursor now lets you run cloud agents inside a <a href="https://cursor.com/blog/cloud-agent-development-environments" target="_blank" rel="noreferrer">fully configured development environment</a>.</p></li><li><p><a href="http://github.com/stablyai/orca" target="_blank" rel="noreferrer">Orca</a> - Claude Code&#39;s agent view but for Codex, OpenCode, Droid and Pi.</p></li><li><p><a href="https://oboe.com/" target="_blank" rel="noreferrer">Oboe</a> - LLMs wrapped in a way that helps you learn.</p></li><li><p><a href="https://interfaces.dev/" target="_blank" rel="noreferrer">Interfaces.dev</a> - A monthly design engineering magazine about building great interfaces.</p></li><li><p><a href="https://x.com/patrick_oshag/status/2054532117410054252" target="_blank" rel="noreferrer">Anthropic CFO Krishna Rao</a> on compute allocation, pricing dynamics and model company economics:</p></li><li><p><a href="https://www.aiiq.org/" target="_blank" rel="noreferrer">AI IQ</a> - frontier AI models, scored on the human IQ scale.</p></li><li><p><a href="https://x.com/eoghan/status/2054238946612367818" target="_blank" rel="noreferrer">Intercom is rebranding</a> the entire company to Fin, their popular AI agent.</p></li><li><p><a href="https://executor.sh/home?try=local" target="_blank" rel="noreferrer">Executor</a> - Convert MCPs/OpenAPIs servers into code mode under the hood, 100% local on your device.</p></li><li><p>How OpenAI built a <a href="https://openai.com/index/building-codex-windows-sandbox/" target="_blank" rel="noreferrer">safe sandbox for Windows</a>.</p></li></ul><hr><h4 id="afters" tabindex="-1">Afters <a class="header-anchor" href="#afters" aria-label="Permalink to &quot;Afters&quot;">​</a></h4><p><a href="https://www.bensbites.com/?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">Share Ben&#39;s Bites</a></p><hr><ul><li><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p></li><li><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben&#39;s Bites</p></li><li><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p></li></ul><blockquote><h6 id="sponsors-who-make-this-newsletter-possible" tabindex="-1"><em>* sponsors who make this newsletter possible 😃</em> <a class="header-anchor" href="#sponsors-who-make-this-newsletter-possible" aria-label="Permalink to &quot;_* sponsors who make this newsletter possible :)_&quot;">​</a></h6><h6 id="wanna-partner-with-us-for-the-next-quarter" tabindex="-1"><em>Wanna partner with us for the next quarter?</em> <a class="header-anchor" href="#wanna-partner-with-us-for-the-next-quarter" aria-label="Permalink to &quot;_Wanna partner with us for the next quarter?_&quot;">​</a></h6><h6 id="email-us-atshanice-bensbites-com-or-k-bensbites-com" tabindex="-1"><em>Email us at<a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></em> <a class="header-anchor" href="#email-us-atshanice-bensbites-com-or-k-bensbites-com" aria-label="Permalink to &quot;_Email us at[shanice@bensbites.com](mailto:shanice@bensbites.com) or [k@bensbites.com](mailto:k@bensbites.com)_&quot;">​</a></h6></blockquote><p>Ben&#39;s Bites is a reader-supported publication. To receive new posts and support my work, consider becoming a free or paid subscriber.</p><hr><h2 id="learn-the-system" tabindex="-1"><a href="https://www.bensbites.com/p/learn-the-system" target="_blank" rel="noreferrer">Learn the system</a> <a class="header-anchor" href="#learn-the-system" aria-label="Permalink to &quot;[Learn the system](https://www.bensbites.com/p/learn-the-system)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-12</em></p><p>Hey folks,</p><p>I watched <a href="https://www.youtube.com/watch?v=lNVa33qUzZ8" target="_blank" rel="noreferrer">this</a> this morning; &#39;Agentic coding is a trap -- and we all fell for it&#39; - it&#39;s surprising relevant past just developers.</p><blockquote><p>enjoyed this because what i took away;<br><strong>learn the system</strong></p><p>to me, this is the difference of vibe coding and agentic engineering. i&#39;m actively trying to learn the system, not the syntax.</p><p>syntax is what i couldn&#39;t grapple when attempting to learn to code. but the system is clicking more for me the more i build</p><p>im miles away from a &#39;competent software engineer&#39; but im only building things for myself, so i dont <em>need</em> to be - but the more i build, the more that clicks into place.</p><p>i didnt realise it when i was slinging no-code in 2018 but it was a version of learning parts of a system to get software to work (webflow - frontend, airtable - database, zapier - api/backend). it had limitations but now i replaced all of that with code.</p><p>having actual competent engineers create skills and systems to help a sloppy codebase or process is helping (as well as better models). but i do rely on that for years i didnt spend learning to code.</p><p>stay curious folks</p></blockquote><p><a href="https://x.com/bentossell/status/2054118034327916874?s=20" target="_blank" rel="noreferrer">tweeted it earlier</a></p><p>Link to the <a href="https://larsfaye.com/articles/agentic-coding-is-a-trap" target="_blank" rel="noreferrer">original blog post</a>.</p><p>And I&#39;ve been tweaking my AGENTS.md + setup files - as I&#39;m getting closer with the &#39;course&#39; I&#39;m reminding myself to not let your docs slip.</p><p><a href="https://substackcdn.com/image/fetch/$s_!cgXh!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F88f08de1-aed6-40ee-ba2d-29cd8a9dc45b_2386x1858.png" target="_blank" rel="noreferrer"></a>there&#39;ll be a lesson on this and i&#39;ll go thru it all</p><p>Oh and…</p><hr><p><em>Ben &#39;s Bites is brought to you by <a href="https://lightfield.app/blog/introducing-skills?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=bens_bites&amp;utm_content=primary_5-12-2026" target="_blank" rel="noreferrer">Lightfield</a></em></p><blockquote><p><strong>Lightfield</strong> is an AI-native CRM that just shipped <strong><a href="https://lightfield.app/blog/introducing-skills?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=bens_bites&amp;utm_content=primary_5-12-2026" target="_blank" rel="noreferrer">Skills</a></strong>. Define any workflow in plain English and trigger it with a sentence. The AI agent executes against your full CRM data graph with code execution, web search, and file I/O. 3,000+ startups on the platform. <a href="https://lightfield.app/blog/introducing-skills?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=bens_bites&amp;utm_content=primary_5-12-2026" target="_blank" rel="noreferrer">Try free</a></p></blockquote><hr><h4 id="headlines-1" tabindex="-1">Headlines <a class="header-anchor" href="#headlines-1" aria-label="Permalink to &quot;Headlines&quot;">​</a></h4><ul><li><p>You can now work with <strong><a href="https://claude.com/blog/agent-view-in-claude-code" target="_blank" rel="noreferrer">all your Claude Code agents in a single window</a></strong> inside the terminal. You can see their status and reply inline to unblock when they need your input. Any running session can be moved to the agent view with /bg.</p></li><li><p><strong><a href="https://x.com/OpenAI/status/2052480800004956323" target="_blank" rel="noreferrer">Codex now works directly in Chrome</a></strong> on macOS and Windows. It can use sites and apps across tabs in the background without taking over your browser.</p></li><li><p>OpenAI also released <strong><a href="https://openai.com/index/advancing-voice-intelligence-with-new-models-in-the-api/" target="_blank" rel="noreferrer">three new Realtime models</a></strong> in the API: Realtime 2 for voice-to-voice use cases with best intelligence, Realtime Translate for audio translation across 70 input and 13 output languages, and Realtime-Whisper for live speech to text.</p></li><li><p>OpenAI released a cyber defence product, <strong><a href="https://openai.com/daybreak/" target="_blank" rel="noreferrer">Daybreak</a></strong>. Their OpenAI&#39;s answer to Anthropic&#39;s Mythos?</p></li><li><p><strong>Thinking Machines</strong> finally have a model to show us (not letting us try though). They are calling them <strong><a href="https://thinkingmachines.ai/blog/interaction-models/" target="_blank" rel="noreferrer">interaction models</a></strong>. Basically models where you can chat with audio and video input with audio outputs. It seems really impressive for the capabilites they are claiming, for example, time awareness, simultaneous speech and visual cues, but all similar products (ChatGPT&#39;s Advanced Voice Mode, Gemini Live) fail when put in users hands.</p></li><li><p><strong><a href="https://openai.com/index/openai-launches-the-deployment-company/" target="_blank" rel="noreferrer">OpenAI is starting a deployment company</a></strong> in partnership with major consulting firms. It acquired a 150-person AI consulting company, &quot;Tomoro&quot;, to set this up and is putting in $4B of initial investment. The goal is to work with other companies and build AI systems for them.</p><ul><li>I think this means they&#39;re going to effectively transform a ton of knowledge workers and upskill them to knowing how to work with agents. ie able to be a builder. And if you&#39;re a builder -&gt; you can use Codex. You can see how it all links 😊</li></ul></li></ul><hr><p><a href="https://www.bensbites.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><h4 id="my-feed-1" tabindex="-1">My feed <a class="header-anchor" href="#my-feed-1" aria-label="Permalink to &quot;My feed&quot;">​</a></h4><ul><li><p>Artificial Analysis is testing rank models + harness combinations together in their <a href="https://artificialanalysis.ai/agents/coding-agents" target="_blank" rel="noreferrer">Coding Agent Index</a>. Among the combinations they have tested, Opus 4.7 with Cursor CLI is on top with GPT-5.5 in Codex and Opus 4.7 in Claude Code at a close second.</p></li><li><p>Ramp trained a small RL model with <a href="https://x.com/RampLabs/status/2052448843099254956" target="_blank" rel="noreferrer">Fast Ask</a> with Prime Intellect for spreadsheet Q&amp;A. They say it beats Opus by 4% on exact match accuracy at Haiku latency.</p></li><li><p><a href="https://docs.replit.com/core-concepts/agent/task-system" target="_blank" rel="noreferrer">Replit Parallel Agents</a> lets Replit Agent break work into tasks, run them in isolated copies of your app, and merge them back after review.</p></li><li><p><a href="https://x.com/brian_lovin/status/2053876320459964524" target="_blank" rel="noreferrer">Notion Skills</a> - Brian Lovin is using a Notion database like an app store for agent skills, with two-way sync to Claude, Codex and other local agents.</p></li><li><p><a href="https://x.com/aidenybai/status/2052780632510775469" target="_blank" rel="noreferrer">React Doctor v2</a> catches bad React code from agents.</p></li><li><p><a href="https://x.com/mvanhorn/status/2052422567181611010" target="_blank" rel="noreferrer">Printing Press</a> - generate agent-native CLIs for apps like Linear, ESPN, Kayak, etc.</p></li><li><p><a href="https://x.com/claudeai/status/2053868592286822443" target="_blank" rel="noreferrer">The Claude Platform on AWS</a> is now generally available. AWS customers get Claude API features with AWS auth, billing and commitment retirement.</p></li><li><p>OpenAI&#39;s API has a new <a href="https://files-sdk.dev/" target="_blank" rel="noreferrer">Files SDK</a> for object and blob storage and an <a href="https://x.com/OpenAIDevs/status/2053925962287583379" target="_blank" rel="noreferrer">OpenAI Developers plugin</a> for Codex to build faster with OpenAI APIs.</p></li><li><p>Parallel AI&#39;s <a href="https://parallel.ai/blog/monitor-api-ga" target="_blank" rel="noreferrer">Monitor API</a> is now GA. It sends web push updates to background agents instead of agents constantly polling for changes.</p></li><li><p><a href="https://github.com/vercel-labs/zero-native" target="_blank" rel="noreferrer">zero-native</a> - build native desktop and mobile apps with web UI.</p></li><li><p>A spec for <a href="https://github.com/vercel-labs/mdxg" target="_blank" rel="noreferrer">how interfaces should present Markdown</a>.</p></li><li><p><a href="https://x.com/jeffreyhuber/status/2054042150019707082" target="_blank" rel="noreferrer">7 Powers in the age of AI</a> for building a company.</p></li><li><p><a href="https://github.com/zenbu-labs/zenbu.js" target="_blank" rel="noreferrer">a framework for hackable software</a> i.e. apps that ship with their raw source code, where users can modify them using coding agents.</p></li><li><p>New research from Anthropic <a href="https://www.anthropic.com/research/natural-language-autoencoders" target="_blank" rel="noreferrer">translates the inner workings of Claude into text</a> and <a href="https://www.anthropic.com/research/teaching-claude-why" target="_blank" rel="noreferrer">teaches it good behaviour</a> using fictional stories.</p></li><li><p><a href="https://x.com/steipete/status/2053114837698249190" target="_blank" rel="noreferrer">Peekaboo 3.0</a> - Peter&#39;s macOS computer-use tool got action-first automation, unified screenshot + UI detection, cleaner JSON and better snapshots.</p></li></ul><hr><h4 id="afters-1" tabindex="-1">Afters <a class="header-anchor" href="#afters-1" aria-label="Permalink to &quot;Afters&quot;">​</a></h4><p><a href="https://www.bensbites.com/?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">Share Ben&#39;s Bites</a></p><hr><ul><li><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p></li><li><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben&#39;s Bites</p></li><li><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p></li></ul><blockquote><h6 id="sponsors-who-make-this-newsletter-possible-1" tabindex="-1"><em>* sponsors who make this newsletter possible 😃</em> <a class="header-anchor" href="#sponsors-who-make-this-newsletter-possible-1" aria-label="Permalink to &quot;_* sponsors who make this newsletter possible :)_&quot;">​</a></h6><h6 id="wanna-partner-with-us-for-the-next-quarter-1" tabindex="-1"><em>Wanna partner with us for the next quarter?</em> <a class="header-anchor" href="#wanna-partner-with-us-for-the-next-quarter-1" aria-label="Permalink to &quot;_Wanna partner with us for the next quarter?_&quot;">​</a></h6><h6 id="email-us-atshanice-bensbites-com-or-k-bensbites-com-1" tabindex="-1"><em>Email us at<a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></em> <a class="header-anchor" href="#email-us-atshanice-bensbites-com-or-k-bensbites-com-1" aria-label="Permalink to &quot;_Email us at[shanice@bensbites.com](mailto:shanice@bensbites.com) or [k@bensbites.com](mailto:k@bensbites.com)_&quot;">​</a></h6></blockquote><p>Ben&#39;s Bites is a reader-supported publication. To receive new posts and support my work, consider becoming a free or paid subscriber.</p><hr><h2 id="ben-s-builds-3-an-email-app" tabindex="-1"><a href="https://www.bensbites.com/p/bens-builds-3-an-email-app" target="_blank" rel="noreferrer">Ben&#39;s Builds #3 - an email app</a> <a class="header-anchor" href="#ben-s-builds-3-an-email-app" aria-label="Permalink to &quot;[Ben&#39;s Builds #3 - an email app](https://www.bensbites.com/p/bens-builds-3-an-email-app)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-09</em></p><p>Hey folks, I had some time to build this week and I mentioned I&#39;d go into a bit more detail on how I did it.</p><p>And at the bottom I&#39;ll touch on the tools I&#39;m using day to day.</p><p><a href="https://www.bensbites.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><h4 id="what-did-i-build-this-week" tabindex="-1">What did I build this week? <a class="header-anchor" href="#what-did-i-build-this-week" aria-label="Permalink to &quot;What did I build this week?&quot;">​</a></h4><p>An email app…</p><p>I use Gmail. I&#39;ve used Superhuman for years. I like it a lot. It is fast, keyboard-first, clean, and is good software. But like many saas products, it keeps adding features that I don&#39;t need and more importantly, I don&#39;t need to be paying for email.</p><p>I wanted a split inbox and rules to organize my emails.</p><p>Kicking off with Codex:</p><p>I&#39;ve got an idea. I want you to build me an email client so I can have things exactly how I want them. I&#39;ll only be using it on my MacBook. It can run locally to start. Gmail should stay the source of truth.</p><p>The end product has split inboxes, shortcuts, command palette, reply/compose, 20 second undo send, one-click unsubscribe, search, rules, filter sync, email rendering (mostly 😬) and built in a way that an agent can use it natively.</p><p><a href="https://substackcdn.com/image/fetch/$s_!DoyP!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F3d22e21c-b04c-4998-b915-21dd90f6eb55_1440x458.png" target="_blank" rel="noreferrer"></a></p><p>The code probably has slop in it, I wasn&#39;t planning on sharing it but others have asked. So I will. But I&#39;m only building it for myself.</p><h3 id="version-1" tabindex="-1">Version 1 <a class="header-anchor" href="#version-1" aria-label="Permalink to &quot;Version 1&quot;">​</a></h3><p>I already have labels I use all the time:</p><ul><li><p>investing - for porfolio companies and LPs</p></li><li><p>fyi - receipts, updates, info I never need to read</p></li><li><p>cal - calendar invites</p></li><li><p>news - newsletters</p></li><li><p>pitch - PR emails that I don&#39;t need to read</p></li></ul><p>I don&#39;t need AI to read every email and categorise it for me - filtering by domain or email address does a great job.</p><p>Codex did the first pass but struggled with the UX/UI so I moved to Factory which handled the polish (I could flit between Opus and GPT 5.5), many fixes, testing and getting the product right (enough).</p><p><a href="https://substackcdn.com/image/fetch/$s_!JdKf!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F330dc4d7-1925-4729-a429-1acc5f4fdc0a_1440x651.png" target="_blank" rel="noreferrer"></a></p><h3 id="first-real-issue" tabindex="-1">First real issue <a class="header-anchor" href="#first-real-issue" aria-label="Permalink to &quot;First real issue&quot;">​</a></h3><p>It was laggy. I&#39;m using the Google Workspace CLI which can authenticate, fetch emails, and update labels - all the actions I need basically. The whole app is built on top of this.</p><p>Investigate why there is a delay with anything in this app. I want everything to feel instant.</p><p>It found the app was pinging Gmail too much, too often.</p><p>So it then started showing cached data immediately, refreshing in the background, prefetching thread details and updating the UI optimistically when I archive or label something.</p><p>This is one of the reasons I like building with agents. I&#39;m learning along the way - <strong>obviously</strong> a database would help here - so we added that.</p><h3 id="labels-and-rules" tabindex="-1">Labels and rules <a class="header-anchor" href="#labels-and-rules" aria-label="Permalink to &quot;Labels and rules&quot;">​</a></h3><p>At first labels were just labels. Press L, pick one, done.</p><p>If I label something investing, it should move to Investing. If a rule says a label skips the inbox, Gmail should remove it from the inbox.</p><p>It&#39;s obvious with Gmail filters but my agent was defaulting to a local rule file and not actually syncing with Gmail. Factory sorted it out thankfully.</p><p><a href="https://substackcdn.com/image/fetch/$s_!mJxc!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fb7ea944e-1fcd-4fd1-9ff6-30c587498dc9_1433x600.png" target="_blank" rel="noreferrer"></a></p><p>Then I decided I wanted to make rules richer - when I add a label rule, I should be able to define if it should happen to all domains or just that specific email address.</p><p>I originally did that with a notification to choose after labelling but then I decided to make it part of the label modal. Code is cheap - try it, then if it feels wrong, change it.</p><p><a href="https://substackcdn.com/image/fetch/$s_!jaWj!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F1e175421-73bd-4913-a4e7-bda711cc789e_1440x1000.png" target="_blank" rel="noreferrer"></a></p><h3 id="making-it-agent-friendly" tabindex="-1">Making it agent-friendly <a class="header-anchor" href="#making-it-agent-friendly" aria-label="Permalink to &quot;Making it agent-friendly&quot;">​</a></h3><p>This app should be usable by agents while I&#39;m talking to them. Add whatever hidden selectors/state/debug endpoints would help agents operate it, but I don&#39;t want to visually see any of that.</p><h3 id="adding-reply-functionality" tabindex="-1">Adding reply functionality <a class="header-anchor" href="#adding-reply-functionality" aria-label="Permalink to &quot;Adding reply functionality&quot;">​</a></h3><p>Then I wanted to be able to reply, obviously.</p><p>Build full reply functionality. Default reply-all, editable to/cc/bcc, attachments. Cmd+Enter sends and archives, but waits 20 seconds before actually sending so Cmd+Z can undo.</p><p>This was a bigger jump than I thought… but after a bunch of UX iterations in Factory it feels pretty good.</p><p><a href="https://substackcdn.com/image/fetch/$s_!exgj!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fc5e82630-d0cd-4aef-84dd-0bbe2082d375_2930x1544.png" target="_blank" rel="noreferrer"></a></p><h3 id="email-rendering" tabindex="-1">Email rendering <a class="header-anchor" href="#email-rendering" aria-label="Permalink to &quot;Email rendering&quot;">​</a></h3><p>Showing email sounds easy until you try to show email.</p><p>Plain text, Gmail HTML, newsletters, receipts, calendar invites, inline images, signatures, quoted replies, tracking pixels, weird MIME stuff. Horrible little world.</p><p>The email renderer needs to handle all kinds of email and display them well. Normal human emails should feel native. Designed newsletters/receipts can render differently. Use good open-source libraries.</p><p>Codex improved the system but with a bunch of specific rules like if this do that.</p><p>So I stepped away and tried to think about other ways to approach it. I know Obsidian has a web clipper that displays nice previews of web pages. So I got Codex to reverse engineer the chrome extension to understand how it works.</p><p>So then I asked to apply that approach to email rendering. It&#39;s still not prefect and I&#39;ve given up on perfect for now so normal emails look good (enough) and html heavy emails (like this newsletter, amazon, etc) just get shown as they are.</p><p><a href="https://substackcdn.com/image/fetch/$s_!whNr!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F8a37d1ea-56ed-480f-8672-d1fbc4cbbe7c_2938x1162.png" target="_blank" rel="noreferrer"></a></p><p>What can we do about signatures? They feel irrelevant.</p><p>But some emails have stupid signatures that look like designed HTML emails. So I got Factory to fix those and essentially hide that part of the email from the user.</p><p>Factory then found one of my favourite bugs. A normal email with a fancy signature rendered like a designed newsletter.</p><p>Why? Logo/table signature. The classifier thought the signature meant the whole email was a designed HTML email.</p><h3 id="search-and-all-mail" tabindex="-1">Search and All Mail <a class="header-anchor" href="#search-and-all-mail" aria-label="Permalink to &quot;Search and All Mail&quot;">​</a></h3><p>Then I added a search page for all my emails.</p><p>And then, All Mail, because sometimes I do need to see what&#39;s been archived.</p><p>But it was a bit off…</p><p>Nah its funky as fuck. Use the browser to test it.</p><p>The fix was to lazy-load All Mail and stop hammering Gmail.</p><p><a href="https://substackcdn.com/image/fetch/$s_!l55G!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ffbd573b8-c766-4319-b4f2-f853709163a7_2940x850.png" target="_blank" rel="noreferrer"></a></p><h3 id="my-takeaways" tabindex="-1">My takeaways <a class="header-anchor" href="#my-takeaways" aria-label="Permalink to &quot;My takeaways&quot;">​</a></h3><p>I don&#39;t advise building an email client 😅.</p><p>If you want a feature (and then another) just build it and see what feels right. Code is cheap.</p><p>Switch between tools (harnesses) and models.</p><p>Think about other tools or apps that may do all or parts of what you&#39;re trying to do. Ask your agent to reverse engineer it.</p><p>Use fresh sessions outside of your project to get unbiased opinions on implementations. Your agent is influenced by everything in it&#39;s context.</p><p>Ask the agent a lot of &quot;I assumed it was doing this, is it?&quot;, &quot;Why does this happen?&quot;, &quot;Whats the best way to do this?&quot;, &quot;What are the tradeoffs of this approach?&quot;</p><p>Get agents to use the browser to test things out, a lot.</p><p>You learn a lot from building for fun or for the sake of it. So just build stuff!</p><hr><h3 id="my-stack" tabindex="-1">My stack <a class="header-anchor" href="#my-stack" aria-label="Permalink to &quot;My stack&quot;">​</a></h3><p>So many tools. So little time.</p><p>Everyone feels the same - so just find tools you need for the job you need to complete. Don&#39;t worry about all the new shiny tools every day.</p><p>Day-to-day &#39;work&#39; i.e. brainstorming, talking about ideas, essentially everything non-coding heavy (like bigger projects or apps) I&#39;m still using <a href="https://pi.dev/" target="_blank" rel="noreferrer">Pi</a>, but now with GPT 5.5 since Anthropic has cracked down…boo! But I&#39;m liking 5.5 - GPT models tend to follow instructions more directly so it really matters what you have in your AGENTS.md and context.</p><p>I&#39;ve also spent the last 2 weeks in the Codex app - it&#39;s really good. Use a VPN if in EU/UK so you can use the chrome and computer use tools. But I still find myself preferring the terminal (with Pi) because you can see everything the agent is doing and jump in to course-correct (or tweak your instructions). But IMO this app is better than the Claude variants. Don&#39;t bother using Cowork - it&#39;s limited and they&#39;ll merge it into Claude Code soon enough - don&#39;t be put off by &#39;code&#39; in the name. All these coding agents are just great general agents.</p><p>For &#39;real&#39; coding i.e. when I&#39;m serious about building something, I use <a href="https://factory.ai" target="_blank" rel="noreferrer">Factory</a>. It&#39;s the best harness for code, especially if you don&#39;t know <em>how to actually</em> <em>code</em>. It&#39;s more complete, and seems to handle everything much more than others I&#39;ve used - plus you can switch between Claude and Opus models very easily. They recently launched a $100 plan too with better limits too.</p><p>For full stack apps I&#39;m sticking with Vercel, Stripe and Supabase. I just started using Stripe&#39;s <a href="https://projects.dev/" target="_blank" rel="noreferrer">projects.dev</a> which will set up all three of those apps (and many others) all in one. Your agent can basically just use projects.dev, set up, manage and link all the other services you need to get apps setup properly. Super helpful as you don&#39;t have to manually add or manage each yourself.</p><p>I use <a href="https://here.now/" target="_blank" rel="noreferrer">here.now</a> <strong>a lot</strong> - I&#39;m always spinning up new sites for random ideas or tasks like visualising data and things of that nature. Plus sites are easier to read than pure documents. Just give the instructions (copy from the homepage) to your agent and you get free websites spun up on-demand. Super slick and easy.</p><p>For document editing and writing I&#39;ve been using <a href="https://clearly.md" target="_blank" rel="noreferrer">Clearly</a> quite a lot recently. I like it - I don&#39;t know what I really want out of a document editor like this, truly I just want to view and edit docs within whichever tool I&#39;m using (pi/droid/codex) but none let you do all of that…yet.</p><p>That&#39;s mostly it - other than a bunch of CLI tools like <a href="https://github.com/yt-dlp/yt-dlp" target="_blank" rel="noreferrer">downloading youtube videos</a> or podcasts, getting transcripts, and I use markdown.new for my agents to easily grab website information (It&#39;s in my AGENTS.md so my agents use it - i.e. <a href="https://markdown.new/www.example.com" target="_blank" rel="noreferrer">https://markdown.new/www.example.com</a> - but I recently discovered defuddle.md which I may switch to).</p><hr><p><a href="https://open.substack.com/pub/bensbites/chat?utm_source=chat_embed" target="_blank" rel="noreferrer">Chat with me</a></p><p>If you know a builder that&#39;d find this useful, feel free to <a href="https://www.bensbites.com/publish/post/https://www.bensbites.com/p/bens-builds-3-an-email-app?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">forward to them</a>.</p><p>Have a great weekend!</p><hr><ul><li><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p></li><li><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben&#39;s Bites</p></li></ul><hr><p>Ben&#39;s Bites is a reader-supported publication. To receive new posts and support my work, consider becoming a free or paid subscriber.</p><hr>',160)])])}const m=t(s,[["render",n]]);export{c as __pageData,m as default};
